class Solution {
    public int magicalString(int n) {
        int[] magical = new int[n];
        magical[0] = 1;
        int index = 0;
        int count = 1;
        int i = 1;
        while (i < n) {
            for (int j = 0; j < magical[index]; j++) {
                if (i < n) {
                    magical[i] = count % 2 + 1;
                    i++;
                }
            }
            index++;
            count++;
        }
        int ones = 0;
        for (int num : magical) {
            if (num == 1) {
                ones++;
            }
        }
        return ones;
    }
}
